                name: `MovePosition Debt`,
                type: "Debt",
                value: value.toFixed(4),
                numericValue: value,
                tokenSymbol: tokenInfo.symbol,
                resourceType: resourceType,
                source: "rpc",
                protocol: PROTOCOL_REGISTRY.MOVEPOSITION,
