    sentryInitialized = true;
    console.log('Sentry error tracking initialized');
  } catch (error) {
    console.error('Failed to initialize Sentry:', error);
  }
}

/**
 * Log an error
 * Sends to Sentry if configured, also logs locally
 * @param {Error|string} error - Error object or message
 * @param {Object} context - Additional context data
 * @param {string} level - Log level (error, warning, info)
 */
export function logError(error, context = {}, level = 'error') {
  const errorMessage = error instanceof Error ? error.message : String(error);
  const errorStack = error instanceof Error ? error.stack : '';

  // Log locally
  const logLevel = {
    error: console.error,
    warning: console.warn,
    info: console.info
  }[level] || console.error;

  logLevel(`[${level.toUpperCase()}] ${errorMessage}`, {
    stack: errorStack,
    context
  });

  // Send to Sentry if initialized
  if (sentryInitialized && import.meta.env.VITE_SENTRY_DSN) {
    try {
      // Sentry.captureException(error, {
      //   level,
      //   contexts: {
      //     ...context
      //   }
      // });
    } catch (e) {
      console.error('Failed to send error to Sentry:', e);
    }
  }
}

/**
 * Log a warning
 * @param {string} message - Warning message
 * @param {Object} context - Additional context data
 */
export function logWarning(message, context = {}) {
  logError(message, context, 'warning');
}

/**
 * Log info message
 * @param {string} message - Info message
 * @param {Object} context - Additional context data
 */
export function logInfo(message, context = {}) {
  if (import.meta.env.VITE_DEBUG_MODE) {
    logError(message, context, 'info');
  }
}

/**
 * Log API request
 * @param {string} method - HTTP method
 * @param {string} url - Request URL
 * @param {number} statusCode - Response status code
 * @param {number} duration - Request duration in ms
 * @param {Object} metadata - Additional metadata
 */
export function logApiRequest(method, url, statusCode, duration, metadata = {}) {
  if (statusCode >= 400) {
    logWarning(`API Error: ${method} ${url} - ${statusCode}`, {
      method,
      url,
      statusCode,
      duration,
      ...metadata
    });
  } else if (import.meta.env.VITE_DEBUG_MODE) {
    logInfo(`API: ${method} ${url} - ${statusCode} (${duration}ms)`, {
      method,
      url,
      statusCode,
      duration,
      ...metadata
    });
  }
}

/**
 * Log blockchain transaction
 * @param {string} txHash - Transaction hash
 * @param {string} status - Status (pending, success, failed)
 * @param {Object} metadata - Transaction metadata
 */
export function logTransaction(txHash, status, metadata = {}) {
  const message = `Transaction ${status}: ${txHash}`;
  
  if (status === 'failed') {
    logError(message, metadata, 'error');
  } else {
    logInfo(message, metadata);
  }
}

/**
 * Create error boundary compatible error logger
 * @param {Error} error - Error from error boundary
 * @param {Object} errorInfo - Error info from error boundary
 */
export function logErrorBoundary(error, errorInfo) {
  logError(error, {
    componentStack: errorInfo.componentStack,
    errorBoundary: true
  }, 'error');
}

/**
 * Setup global error handlers
 */
export function setupGlobalErrorHandlers() {
  // Catch uncaught errors
  window.addEventListener('error', (event) => {
    logError(event.error, {
      filename: event.filename,
      lineno: event.lineno,
      colno: event.colno,
      type: 'uncaught'
    }, 'error');
  });

  // Catch unhandled promise rejections
  window.addEventListener('unhandledrejection', (event) => {
    logError(event.reason, {
      type: 'unhandledRejection'
    }, 'error');
  });

  // Log performance issues
  if ('PerformanceObserver' in window) {
    try {
      const observer = new PerformanceObserver((list) => {
        for (const entry of list.getEntries()) {
          if (entry.duration > 3000) { // Log slow operations (>3s)
            logWarning(`Slow operation: ${entry.name} - ${entry.duration.toFixed(0)}ms`, {
              type: 'performance',
              name: entry.name,
              duration: entry.duration
            });
          }
        }
      });

      observer.observe({ entryTypes: ['measure', 'navigation'] });
    } catch (e) {
      // PerformanceObserver not available or error
    }
  }
}

/**
 * Log performance metric
 * @param {string} name - Metric name
 * @param {number} value - Metric value
 */
export function logMetric(name, value) {
  if (import.meta.env.VITE_DEBUG_MODE) {
    console.log(`Metric: ${name} = ${value}`);
  }

  // Could send to analytics service here
  // analytics.track('metric', { name, value });
}

export default {
  initializeSentry,
  logError,
  logWarning,
  logInfo,
  logApiRequest,
  logTransaction,
  logErrorBoundary,
  setupGlobalErrorHandlers,
  logMetric
};

/**
 * Movement Network Indexer Service
 * GraphQL API client for querying Movement Network indexer
 * Documentation: https://docs.movementnetwork.xyz/devs/indexing
 */

import { DEFAULT_NETWORK } from "../config/network";

/**
 * Get the appropriate indexer endpoint based on network
 */
export const getIndexerEndpoint = () => {
  return DEFAULT_NETWORK.indexer;
};

/**
 * Execute a GraphQL query against the Movement Indexer
 * @param {string} query - GraphQL query string
 * @param {Object} variables - Query variables
 * @returns {Promise<Object>} Query result
 */
export const queryIndexer = async (query, variables = {}) => {
  const endpoint = getIndexerEndpoint();
  
  try {
    const response = await fetch(endpoint, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        query,
        variables,
      }),
    });

    if (!response.ok) {
      throw new Error(`Indexer API error: ${response.status} ${response.statusText}`);
    }

    const result = await response.json();
    
    if (result.errors) {
      throw new Error(`GraphQL errors: ${JSON.stringify(result.errors)}`);
    }

    return result.data;
  } catch (error) {
    throw error;
  }
};

/**
 * Normalize address for GraphQL queries (lowercase, ensure 0x prefix)
 */
const normalizeAddress = (address) => {
  if (!address) return "";
  
  let normalized = String(address).trim();
  
  // Handle AccountAddress objects from SDK
  if (normalized.startsWith("0x") || /^[a-fA-F0-9]+$/.test(normalized)) {
    // Already looks like hex
  } else if (typeof normalized === "string" && normalized.length > 0) {
    // Try to extract hex from object string representation
    const hexMatch = normalized.match(/0x[a-fA-F0-9]+/i);
    if (hexMatch) {
      normalized = hexMatch[0];
    }
  }
  
  // Ensure 0x prefix
  if (!normalized.startsWith("0x")) {
    normalized = `0x${normalized}`;
  }
  
  // Lowercase for consistency (GraphQL is case-sensitive)
  normalized = normalized.toLowerCase();
  
  return normalized;
};

/**
 * Check if an account exists on chain (has any transactions or balances)
 * @param {string} address - Wallet address
 * @returns {Promise<{exists: boolean, txCount: number}>}
 */
export const checkAccountExists = async (address) => {
  const normalizedAddress = normalizeAddress(address);
  if (!normalizedAddress || normalizedAddress === "0x") {
    return { exists: false, txCount: 0 };
  }

  const query = `
    query CheckAccountExists($address: String!) {
      account_transactions_aggregate(
        where: { account_address: { _eq: $address } }
      ) {
        aggregate {
          count
        }
      }
    }
  `;

  try {
    const data = await queryIndexer(query, { address: normalizedAddress });
    const txCount = data?.account_transactions_aggregate?.aggregate?.count || 0;
    return { exists: txCount > 0, txCount };
  } catch (error) {
    console.warn("checkAccountExists error:", error);
    return { exists: false, txCount: 0 };
  }
};

